#include <stdio.h>
#include <stdlib.h>

// Comparator for sorting based on start time
int compare(const void *a, const void *b) {
    int *pairA = (int *)a;
    int *pairB = (int *)b;
    return pairA[0] - pairB[0];
}

// Binary search to find the next event
int binarySearch(int sortedStartTimes[][2], int size, int target) {
    int left = 0, right = size - 1;
    while (left <= right) {
        int mid = left + (right - left) / 2;
        if (sortedStartTimes[mid][0] >= target) {
            right = mid - 1;
        } else {
            left = mid + 1;
        }
    }
    return (left < size) ? sortedStartTimes[left][1] : -1;
}

// Function to find the next event for each event
void findNextEvent(int n, int events[][2], int result[]) {
    int sortedStartTimes[n][2];

    // Store start times with their original indices
    for (int i = 0; i < n; i++) {
        sortedStartTimes[i][0] = events[i][0];
        sortedStartTimes[i][1] = i;
    }

    // Sort based on start time
    qsort(sortedStartTimes, n, sizeof(sortedStartTimes[0]), compare);

    // Find the next event for each event using binary search
    for (int i = 0; i < n; i++) {
        result[i] = binarySearch(sortedStartTimes, n, events[i][1]);
    }
}

