import java.util.*;

public class Main {
    public static int[] findNextEvent(int[][] events) {
        int n = events.length;
        int[][] startTimes = new int[n][2]; // To store {start_time, original_index}

        for (int i = 0; i < n; i++) {
            startTimes[i][0] = events[i][0];
            startTimes[i][1] = i;
        }

        // Sort startTimes based on start_time
        Arrays.sort(startTimes, Comparator.comparingInt(a -> a[0]));

        int[] result = new int[n];
        Arrays.fill(result, -1);

        for (int i = 0; i < n; i++) {
            int endTime = events[i][1];

            // Binary search to find the first event with start_time >= endTime
            int left = 0, right = n - 1;
            while (left <= right) {
                int mid = left + (right - left) / 2;
                if (startTimes[mid][0] >= endTime) {
                    right = mid - 1;
                } else {
                    left = mid + 1;
                }
            }

            if (left < n) {
                result[i] = startTimes[left][1];
            }
        }

        return result;
    }

    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);

        int n = sc.nextInt();
        int[][] events = new int[n][2];

        for (int i = 0; i < n; i++) {
            events[i][0] = sc.nextInt();
            events[i][1] = sc.nextInt();
        }

        int[] result = findNextEvent(events);

        for (int val : result) {
            System.out.print(val + " ");
        }
    }
}

