function findNextEvent(events) {
    const n = events.length;
    const startTimes = events.map((event, i) => [event[0], i]);
    startTimes.sort((a, b) => a[0] - b[0]);

    const result = Array(n).fill(-1);

    for (let i = 0; i < n; i++) {
        const endTime = events[i][1];

        // Binary search to find the first event with start_time >= endTime
        let left = 0, right = n - 1;
        while (left <= right) {
            const mid = Math.floor((left + right) / 2);
            if (startTimes[mid][0] >= endTime) {
                right = mid - 1;
            } else {
                left = mid + 1;
            }
        }

        if (left < n) {
            result[i] = startTimes[left][1];
        }
    }

    return result;
}

